import requests
import json

# Define Kong admin credentials
kong_admin = "http://localhost:8001"
username = "admin"
password = "admin"

# Set up headers and payload
headers = {
    'Content-Type': 'application/x-www-form-urlencoded'
}

def create_service(service_name, host, port):
    url = f"{kong_admin}/services"
    payload = {
        'name': service_name,
        'host': host,
        'port': port
    }
    response = requests.post(url, headers=headers, auth=(username, password), data=payload)
    if response.status_code == 201:
        print(f"Service {service_name} created successfully")
    else:
        print(f"Failed to create service {service_name}")

def create_route(service_name):
    url = f"{kong_admin}/routes"
    payload = {
        'protocols': ['http'],
        'paths': ["/"],
        'methods': ["GET", "POST"],
        'service': {'connection': service_name}
    }
    response = requests.post(url, headers=headers, auth=(username, password), data=payload)
    if response.status_code == 201:
        print(f"Route created for service {service_name}")
    else:
        print(f"Failed to create route for service {service_name}")

def create_upstream(service_name):
    url = f"{kong_admin}/upstreams"
    payload = {
        'name': service_name,
        'algorithm': 'round-robin'
    }
    response = requests.post(url, headers=headers, auth=(username, password), data=payload)
    if response.status_code == 201:
        print(f"Upstream created for service {service_name}")
    else:
        print(f"Failed to create upstream for service {service_name}")

def link_upstream_to_route(service_name):
    url = f"{kong_admin}/routes"
    payload = {
        'protocols': ['http'],
        'paths': ["/"],
        'methods': ["GET", "POST"],
        'service': {'connection': service_name},
        'upstreams': [{'node': {'service': {'id': f'{service_name}'}}}]
    }
    response = requests.post(url, headers=headers, auth=(username, password), data=payload)
    if response.status_code == 201:
        print(f"Upstream linked to route for service {service_name}")
    else:
        print(f"Failed to link upstream to route for service {service_name}")

# Create services
create_service("my-service", "localhost", 8080)

# Create routes and link them to services
create_route("my-service")

# Create upstream targets and link them to routes
create_upstream("my-service")
link_upstream_to_route("my-service")